<script>
import JX3BOX from "@jx3box/jx3box-common/data/jx3box.json";
import { showDate, showTime } from "@jx3box/jx3box-common/js/moment";
import { editLink, authorLink } from "@jx3box/jx3box-common/js/utils.js";
import User from "@jx3box/jx3box-common/js/user.js";
import i18nMixin from "../../i18n/mixin";
const { __clients } = JX3BOX;

export default {
    name: "PostHeader",
    mixins: [i18nMixin],
    props: {
        post: {
            type: Object,
            default: () => ({}),
        },
        stat: {
            type: Object,
            default: () => ({}),
        },
        titleExtra: {
            type: String,
            default: "",
        },
        anonymous: {
            type: Boolean,
            default: false,
        },
    },
    data: function () {
        return {
            wordCount: 0,
        };
    },
    computed: {
        url: function () {
            return location.href;
        },
        isOriginal: function () {
            return !!~~this.post?.original;
        },
        title: function () {
            return this.post?.post_title || this.$jx3boxT("jx3boxUi.postHeader.noTitle", "无标题");
        },
        author_link: function () {
            return authorLink(this.post?.post_author);
        },
        author_name: function () {
            return this.post?.author_info?.display_name || this.$jx3boxT("jx3boxUi.postHeader.anonymous", "匿名");
        },
        post_date: function () {
            return showDate(new Date(this.post?.post_date));
        },
        update_date: function () {
            return showDate(new Date(this.post?.post_modified));
        },
        post_time: function () {
            return showTime(new Date(this.post?.post_date));
        },
        update_time: function () {
            return showTime(new Date(this.post?.post_modified));
        },
        views: function () {
            return this.stat?.views || "-";
        },
        edit_link: function () {
            return editLink(this.post?.post_type, this.post?.ID);
        },
        canEdit: function () {
            return this.post?.post_author == User.getInfo().uid || User.isEditor();
        },
        client: function () {
            return this.post?.client || "std";
        },
        is_wujie: function () {
            return this.post?.is_wujie;
        },
    },
    watch: {
        post: {
            deep: true,
            immediate: true,
            handler: function () {
                this.countWords();
            },
        },
    },
    methods: {
        showClientLabel: function (val) {
            return __clients[val];
        },
        countWords: function () {
            this.$nextTick(() => {
                const target = document.querySelector(".c-article");
                if (target) {
                    this._doCount(target);
                    this._observeTarget(target);
                } else {
                    this._observeBody();
                }
            });
        },
        _doCount: function (target) {
            // 需要去除空格 \n \g
            // eslint-disable-next-line no-useless-escape
            const text = target.textContent?.replace(
                /[\s|\n|\r|\t|\g|\ |\~|\`|\!|\@|\#|\$|\%|\^|\&|\*|\(|\)|\-|\_|\+|\=|\||\\|\[|\]|\{|\}|\;|\:|\"|\'|\,|\<|\.|\>|\/|\?|\，|\。|\？|\：|\；|\‘|\’|\”|\“|\、|\·|\！|\（|\）|\》|\《|\『|\』]/g,
                ""
            );

            this.wordCount = text?.length || 0;
        },
        _observeTarget: function (target) {
            if (this.targetObserver) this.targetObserver.disconnect();
            this.targetObserver = new MutationObserver(() => {
                this._doCount(target);
            });
            this.targetObserver.observe(target, {
                childList: true,
                subtree: true,
                characterData: true,
            });
        },
        _observeBody: function () {
            if (this.bodyObserver) return;
            this.bodyObserver = new MutationObserver((mutations, observer) => {
                const target = document.querySelector(".c-article");
                if (target) {
                    this._doCount(target);
                    this._observeTarget(target);
                    observer.disconnect();
                    this.bodyObserver = null;
                }
            });
            this.bodyObserver.observe(document.body, {
                childList: true,
                subtree: true,
            });
        },
    },
    mounted: function () {
        this.countWords();
    },
    beforeUnmount: function () {
        if (this.targetObserver) this.targetObserver.disconnect();
        if (this.bodyObserver) this.bodyObserver.disconnect();
    },
};
</script>

