nt: #4338ca;\n@v4primary500: #615fff;\n\n@v4border: #c7d2fe;\n@v4bg: #f2f5ff;\n\n@v4text: #4f667d;\n@v4tip: #989cb1;\n\n@v4focus: #efb23e;\n@v4orange: #ec9c0f;\n@v4yellow: #f5bd1e;\n\n@v4pink: #f9c;\n\n// 布局（全局公共组件）\n@header-height: 60px;\n@header-logo-size: 32px;\n@header-bg: #242424;\n@bread-height: 48px;\n\n@aside-left: 320px;\n@aside-right: 280px;\n\n@footer-bg: #121827;\n\n// 适配\n@4k: 3840px;\n@2k: 2560px;\n@pc: 1920px;\n@smallpc: 1680px; //21寸显示器\n@notebook: 1440px; //笔记本电脑\n@mininote: 1280px; //小屏笔记本\n@ipad: 1133px; //平板，适配到8.3mini6\n@ipad-y: 1023px; //竖屏\n@game: 780px; //游戏内嵌\n@phone: 720px; //手机\n@ip5: 374px; //iphone5超小屏\n\n/* assets/css/var.less */\n// ⚠️请勿删除\n/* assets/css/mixin.less */\n// ⚠️请勿删除\n\n// 三角\n.u-delta() {\n    .pa;\n    background-clip: padding-box;\n    background-color: #fff;\n    color: @color;\n    border: 1px solid rgba(27, 31, 35, 0.15);\n    border-radius: 4px;\n    box-shadow: 0 3px 12px rgba(0, 0, 0, 0.1);\n    right: -5px;\n    list-style: none;\n    margin: -6px 0 0 0;\n    position: absolute;\n    z-index: 820;\n    top: 100%;\n\n    &:before {\n        content: \"\";\n        display: inline-block;\n        position: absolute;\n        left: auto;\n        right: 14px;\n        top: -16px;\n        border: 8px solid transparent;\n        border-bottom-color: rgba(27, 31, 35, 0.15);\n    }\n\n    &:after {\n        content: \"\";\n        display: inline-block;\n        position: absolute;\n        left: auto;\n        right: 15px;\n        top: -14px;\n        border: 7px solid transparent;\n        border-bottom-color: #fff;\n    }\n}\n/*\n * Base.less\n * Author: iRuxu\n * Description: a simple and easy-to-use CSS framework, providing common writing combinations\n * Manual: http://csslab.cc\n */\n\n\n/* Font -------------------------------------*/\n\n    // Font size & line height\n    .fz(@font-size, @line-height: false) {\n        font-size: @font-size;\n        & when not (@line-height = false) {\n            line-height: @line-height;\n        }\n    }\n\n    // line height\n    .lh(@line-height, @height: false) {\n        line-height: @line-height;\n        & when not (@height = false) {\n            height: @height;\n        }\n    }\n\n    // Font style\n    .bold(@bold:bold){font-weight:@bold;}\n\n    .italic(){font-style:italic;}\n\n    .normal(){font-weight:normal;font-style:normal;}\n\n    .smooth(){\n        -webkit-font-smoothing:antialiased;\n        -moz-osx-font-smoothing:grayscale;\n    }\n\n    // Number\n    .number(@font-family: false) {\n        & when (@font-family = true) {\n            font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, \"Liberation Mono\", monospace;\n        }\n\n        & when (isstring(@font-family)) {\n            font-family: e(@font-family);\n        }\n\n        font-variant-numeric: tabular-nums slashed-zero;\n        font-feature-settings: \"tnum\" 1, \"zero\" 1;\n    }\n\n    // Font-Face\n    // 注意传参时，name后接分号\n    .fontface(@name; @sources...) {\n        @font-face {\n            font-family: @name;\n            src: @sources;\n            font-display: swap;\n        }\n    }\n\n    // Font color\n    .color(@color, @hovercolor: null) {\n        // 检查是否为纯色\n        & when (iscolor(@color)) {\n            color: @color;\n\n            & when (iscolor(@hovercolor)) {\n                &:hover {\n                    color: @hovercolor;\n                }\n            }\n        }\n        // 非纯色处理（背景填充逻辑）\n        & when not (iscolor(@color)) {\n            -webkit-background-clip: text;\n            -webkit-text-fill-color: transparent;\n            background-image: @color;\n        }\n    }\n\n    // Underline\n    .underline() {\n        .underline(3px, solid, currentColor);\n    }\n\n    .underline(@color) when (iscolor(@color)) {\n        .underline(3px, solid, @color);\n    }\n\n    .underline(@offset, @style, @color) {\n        text-decoration: underline;\n        text-decoration-color: @color;\n        text-decoration-style: @style;\n        text-underline-offset: @offset;\n    }\n\n\n/* Word -------------------------------------*/\n\n    // 不折行\n    .nobreak(@style:ellipsis){\n        white-space:nowrap;\n        word-break:keep-all;\n\n        word-wrap:normal;\n        overflow-wrap: normal;\n\n        text-overflow:@style;\n        overflow:hidden;\n    }\n\n    // 折行\n    .break(@lines: auto, @inline: false) {\n        // 单行折行处理\n        & when (@lines = auto) {\n            white-space: normal;\n            word-break: break-all;\n            word-wrap: break-word;\n            overflow-wrap: break-word;\n            hyphens: auto;\n            line-break: strict;\n        }\n        // 多行折行处理\n        & when not (@lines = auto) {\n            display: if(@inline, -webkit-inline-box, -webkit-box);\n            -webkit-line-clamp: @lines;\n            -webkit-box-orient: vertical;\n            overflow: hidden;\n        }\n    }\n\n    // Special Write Mode\n    // 书写模式：牌匾从右至左水平单行排版效果\n    .retext(x){direction:rtl;unicode-bidi:bidi-override;}\n    // 书写模式：文笺从右至左、从上至下排版效果\n    .retext(y){writing-mode:vertical-rl;text-combine-upright: all;}\n\n    // Text Indent\n    .indent(@indent:-200%){\n        text-indent:@indent;\n        overflow:hidden;\n    }\n\n\n/* Inline(-Block) Align -------------------------------------*/\n\n    //水平（x轴）对齐方式\n    .x(@align:center){text-align:@align;}\n    .auto(x){margin-left:auto;margin-right:auto;}\n\n    //垂直（y轴）对齐方式\n    .y(@align:middle){vertical-align:@align;}\n    .auto(y){display:table-cell;vertical-align:middle;}\n\n    //层叠级别（z轴）\n    .z(@index:1){z-index:@index;}\n\n\n/* Box -------------------------------------*/\n\n    .w(@width){width:@width;}\n    .h(@height){height:@height;}\n    .size(@width,@height:@width){width:@width;height:@height;}\n    .ratio(@ratio){aspect-ratio:@ratio;}\n\n    .db(){display:block;}\n    .none(){display:none;}\n\n    .r(@radius){border-radius:@radius;}\n\n\n/* Layout -------------------------------------*/\n\n\n    .flex(){display:flex;}\n    .flex(x){display:flex;justify-content:center;}\n    .flex(y){display:flex;align-items:center;}\n    .flex(o){display:flex;justify-content:center;align-items:center;}\n\n    .grid(){display:grid;}\n    .grid(@rows, @cols) {\n        display: grid;\n        grid-template-rows: repeat(@rows, 1fr);\n        grid-template-columns: repeat(@cols, 1fr);\n    }\n    .grid(x, @count) {\n        display: grid;\n\n        // 无单位数字：固定列数\n        & when (isnumber(@count)) and (isunit(@count, \"\")) {\n            grid-template-columns: repeat(@count, minmax(0, 1fr));\n        }\n\n        // 带单位数值（px/%/rem/...）：auto-fill + minmax\n        & when (isnumber(@count)) and not (isunit(@count, \"\")) {\n            grid-template-columns: repeat(auto-fill, minmax(@count, 1fr));\n        }\n    }\n    .gap(@value) {\n        @supports (gap: 1px) {\n            gap: @value;\n        }\n\n        @supports not (gap: 1px) {\n            > * {\n                margin-right: @value;\n            }\n\n            > *:last-child {\n                margin-right: 0;\n            }\n        }\n    }\n\n    .ps(){position:static;}\n    .pr(){position:relative;}\n    .pa(){position:absolute;}\n    .pf(){position:fixed;}\n\n    .lt(@l,@t:@l){left:@l;top:@t;}\n    .rt(@r,@t:@r){right:@r;top:@t;}\n    .lb(@l,@b:@l){left:@l;bottom:@b;}\n    .rb(@r,@b:@r){right:@r;bottom:@b;}\n\n\n/* UI -------------------------------------*/\n\n    .pointer(){cursor:pointer;}\n\n    .noclick(){pointer-events:none;}\n\n    .scrollbar(@w:4px,@color:#fafafa,@thumb:#eee) {\n        &::-webkit-scrollbar {\n            width: @w;\n        }\n        &::-webkit-scrollbar-track,\n        &::-webkit-scrollbar-track-piece {\n            background-color: @color;\n            border-radius: @w + 2px;\n        }\n        &::-webkit-scrollbar-thumb {\n            background-color: @thumb;\n            border-radius: @w + 2px;\n        }\n        &::-webkit-scrollbar-button,\n        &::-webkit-scrollbar-corner,\n        &::-webkit-resizer {\n            display: none;\n        }\n    }\n\n\n/* IE余孽 -------------------------------------*/\n\n    // min-*\n    .min-width(@min-width){min-width:@min-width;_width:@min-width;}\n    .min-height(@min-height){min-height:@min-height;_height:@min-height;}\n\n    // display\n    .dbi(){display:inline-block;} //表现为内联块级元素，兼容IE6\n    .clip(){overflow:hidden;} //兼容IE6-7\n\n    // float\n    .fl(){float:left;}      //IE6-7双倍margin bug处理\n    .fr(){float:right;}\n    .clearfix(){ //清除浮动塌陷\n        \n        &:after{content:\"\";display:table;clear:both;}\n    }\n    .clear(@clear:both){clear:@clear;} //清除浮动\n\n\n/* Deprecated -------------------------------------*/\n\n    .pl(@padding){padding-left:@padding;}\n    .pr(@padding){padding-right:@padding;}\n    .pt(@padding){padding-top:@padding;}\n    .pb(@padding){padding-bottom:@padding;}\n    .ml(@margin){margin-left:@margin;}\n    .mr(@margin){margin-right:@margin;}\n    .mt(@margin){margin-top:@margin;}\n    .mb(@margin){margin-bottom:@margin;}\n\n    .tm(@tm){\n        @alpha:@tm*100;\n        opacity:@tm; //ie9 webkit etc.\n        filter:alpha(opacity=@alpha); //ie5-ie7\n    }\n\n\n\n\n/* src/header/client.vue */\n.c-header-client {\n    .pr;\n    height: @header-height;\n\n    * {\n        .pointer;\n    }\n\n    .u-trigger {\n        .pr;\n        height: 100%;\n        padding: 0 16px;\n        .flex(y);\n        gap: 8px;\n        border: 0;\n        background: transparent;\n        color: #fff;\n        // 为iOS添加触摸反馈\n        -webkit-tap-highlight-color: rgba(0, 0, 0, 0.1);\n\n        &::after {\n            content: \"\";\n            .db;\n            .pa;\n            .lb(0);\n            .w(90px);\n            .h(2px);\n            background-color: #e19f3a;\n            opacity: 0;\n            transition: opacity 0.2s ease;\n        }\n\n        // 菜单打开时显示激活条\n        &.is-active::after {\n            opacity: 1;\n        }\n    }\n\n    .u-client--current {\n        background-color: @v4primary500;\n        .r(4px);\n        padding: 2px 5px;\n        .flex(y);\n        gap: 4px;\n        white-space: nowrap;\n\n        span {\n            color: #fff !important;\n            font-size: 14px;\n            font-weight: 500;\n            line-height: 20px;\n        }\n        .u-arrow {\n            width: 12px;\n            height: 12px;\n            fill: #fff !important;\n            transition: transform 0.3s ease;\n\n            &.is-open {\n                transform: rotate(180deg);\n            }\n        }\n    }\n\n    .u-menu {\n        .pa;\n        top: 100%;\n        left: 0;\n        z-index: 50;\n        width: 224px;\n        padding: 8px 0;\n        overflow: hidden;\n        background: #242424;\n        border: 1px solid #374151;\n        border-top: 0;\n        border-radius: 0 0 8px 8px;\n        box-shadow: 0 18px 32px rgba(0, 0, 0, 0.32);\n        transform: translateY(-8px);\n        transform-origin: top;\n        opacity: 0;\n        visibility: hidden;\n        pointer-events: none;\n        transition: opacity 0.2s ease, transform 0.2s ease, visibility 0.2s ease;\n\n        &.is-open {\n            transform: translateY(0);\n            opacity: 1;\n            visibility: visible;\n            pointer-events: auto;\n        }\n    }\n\n    .u-menu__title {\n        padding: 8px 12px;\n        margin-bottom: 4px;\n        color: #6b7280;\n        border-bottom: 1px solid #1f2937;\n        font-size: 10px;\n        line-height: 14px;\n        letter-spacing: 0.08em;\n        text-transform: uppercase;\n    }\n\n    .u-menu__item {\n        .flex;\n        align-items: center;\n        justify-content: space-between;\n        gap: 12px;\n        padding: 12px 16px;\n        color: #e5e7eb;\n        text-decoration: none;\n        transition: background-color 0.2s ease, color 0.2s ease;\n\n        &:hover,\n        &:active {\n            background-color: rgb(79, 70, 229);\n            color: #fff;\n\n            .u-game__name {\n                color: #fff;\n            }\n\n            .u-game__host {\n                color: #c7d2fe;\n            }\n\n            .u-game__icon {\n                color: #fff;\n            }\n        }\n    }\n\n    .u-game {\n        .flex(y);\n        min-width: 0;\n    }\n\n    .u-game__icon {\n        .flex(x);\n        flex: 0 0 auto;\n        width: 16px;\n        height: 16px;\n        margin-right: 12px;\n\n        &,\n        svg,\n        img {\n            width: 16px !important;\n            height: 16px !important;\n        }\n\n        svg,\n        img {\n            display: block;\n        }\n\n        &--std {\n            color: #818cf8;\n        }\n\n        &--origin {\n            color: #fbbf24;\n        }\n    }\n\n    .u-game__text {\n        min-width: 0;\n    }\n\n    .u-game__name {\n        color: #e5e7eb;\n        font-size: 14px;\n        font-weight: 700;\n        line-height: 20px;\n        white-space: nowrap;\n    }\n\n    .u-game__host {\n        color: #6b7280;\n        font-size: 10px;\n        line-height: 14px;\n        white-space: nowrap;\n    }\n\n    .u-dot {\n        flex: 0 0 auto;\n        width: 8px;\n        height: 8px;\n        border-radius: 50%;\n        background: #fbbf24;\n\n        &.is-hidden {\n            visibility: hidden;\n        }\n    }\n}\n"],"sourceRoot":""}]);
