<template>
    <div class="w-thx">
        <template v-if="type === 'batchReward'">
            <batch-reward
                v-if="hasRight && adminBoxcoinEnable && boxcoin_enable"
                :postType="postType"
                :items="postId"
                :boxcoin="boxcoin"
                :userId="userId"
                :own="admin_left"
                :points="admin_points"
                :authors="authors"
                :client="finalClient"
                :max="admin_max"
                :min="admin_min"
                :total="admin_total"
                :category="category"
                :postId="postId"
                @updateRecord="updateRecord"
            />
        </template>
        <template v-else>
            <div class="w-thx-panel">
                <boxcoin-admin
                    :postId="postId"
                    :postType="postType"
                    v-if="hasRight && adminBoxcoinEnable && boxcoin_enable && hasPermission"
                    :userId="userId"
                    :max="admin_max"
                    :min="admin_min"
                    :own="admin_left"
                    :total="admin_total"
                    :points="admin_points"
                    :authors="authors"
                    @updateRecord="updateRecord"
                    :client="finalClient"
                    :totalLimit="total_limit"
                    :postTypeUsed="post_type_used"
                    :category="category"
                />
                <Like :postId="postId" :postType="postType"></Like>
                <fav :postId="postId" :postType="postType" :postTitle="postTitle" :author_id="postAuthorId"></fav>
                <Rss v-if="showRss" :type="postType" :id="postId" :title="postTitle" :author_id="postAuthorId"></Rss>
                <boxcoin-user
                    :postId="postId"
                    :postType="postType"
                    :boxcoin="boxcoin"
                    :userId="userId"
                    :own="user_left"
                    :points="user_points"
                    :authors="authors"
                    v-if="userBoxcoinEnable && boxcoin_enable && allowGift"
                    @updateRecord="updateRecord"
                    :client="finalClient"
                    :category="category"
                    :can-gift="lvEnough"
                />
                <watch-later
                    :category="postType"
                    :title="postTitle"
                    :author-id="postAuthorId"
                    :banner="banner"
                    :content-id="contentMetaId"
                ></watch-later>
                <Share :postId="postId" :postType="postType" :client="client" />
            </div>
            <div class="w-thx-records">
                <boxcoin-records
                    :postId="postId"
                    :postType="postType"
                    :postClient="finalClient"
                    :cacheRecord="cacheRecord"
                    :mode="mode"
                    @update:boxcoin="updateBoxcoin"
                    v-if="showRecord"
                />
            </div>
            <div class="w-thx-copyright">
                &copy;
                {{
                    $jx3boxT(
                        "jx3boxUi.thx.copyright1",
                        "所有原创作品，著作权归作者所有，所有未经授权的非署名转载或抄袭将有权追究法律责任，所有法律事务由专聘律师代理。"
                    )
                }}<br />
                {{
                    $jx3boxT(
                        "jx3boxUi.thx.copyright2",
                        "签约作者独家特约稿件，及所有魔盒官方评分作品用户一经兑现则视为有偿付费稿件，所有商业稿件的转载引用需同时征得魔盒平台授权。"
                    )
                }}
            </div>
        </template>
    </div>
</template>

<script>
import Like from "../interact/Like.vue";
import Fav from "../interact/Fav.vue";
import BatchReward from "../interact/BatchReward.vue";
import BoxcoinAdmin from "../interact/BoxcoinAdmin.vue";
import BoxcoinUser from "../interact/BoxcoinUser.vue";
import BoxcoinRecords from "../interact/BoxcoinRecords.vue";
import Share from "../interact/Share.vue";
import WatchLater from "../interact/WatchLater.vue";
import Rss from "../interact/Rss.vue";

import User from "@jx3box/jx3box-common/js/user";
import { getBoxcoinStatus, getPostBoxcoinConfig } from "../../service/thx";
import { getConfig, getUserPermission } from "../../service/cms";
import i18nMixin from "../../i18n/mixin";

export default {
    name: "ThxComp",
    mixins: [i18nMixin],
    components: {
        Like,
        Fav,
        BatchReward,
        BoxcoinAdmin,
        BoxcoinUser,
        BoxcoinRecords,
        Share,
        WatchLater,
        Rss,
    },
    props: {
        type: {
            type: String,
            default: "normal",
        },
        postId: {
            type: [Number, String, Array],
            default: 0,
        },
        postType: {
            type: String,
            default: "",
        },
        postTitle: {
            type: String,
            default: "",
        },
        userId: {
            type: [Number, String],
            default: 0,
        },
        authors: {
            type: Array,
            default: () => [],
        },
        mode: {
            type: String,
            default: "normal",
        },
        client: {
            type: String,
            default: "std",
        },
        allowGift: {
            type: [Number, Boolean],
            default: 1,
        },
        adminBoxcoinEnable: {
            type: Boolean,
            default: false,
        },
        userBoxcoinEnable: {
            type: Boolean,
            default: false,
        },
        showRss: {
            type: Boolean,
            default: false,
        },
        authorId: {
            type: [Number, String],
            default: 0,
        },
        banner: {
            type: String,
            default: "",
        },
        contentMetaId: {
            type: [Number, String],
            default: 0,
        },
        category: {
            type: String,
            default: "",
        },
    },
    data: function () {
        return {
            boxcoin: 0,
            hasRight: User.getInfo().group >= 64,
            user: User.getInfo(),

            admin_max: 0,
            admin_min: 0,
            admin_left: 0,
            admin_total: 0,
            admin_points: [100],
            total_limit: 0,
            post_type_used: 0,

            user_left: 0,
            user_points: [100],

            cacheRecord: null,
            boxcoin_enable: 0,

            showDrawer: false,

            admin_boxcoin_visible: 1,
            hasPermission: false,

            lvEnough: false, // 用户等级是否足够
        };
    },
    computed: {
        post_keys: function () {
            return [this.postId, this.postType];
        },
        finalClient: function () {
            if (this.client == "wujie") {
                return "std";
            }
            return this.client;
        },
        postAuthorId: function () {
            return this.authorId || this.userId;
        },
        showRecord() {
            // 当admin_boxcoin_visible为0时，作者本人和64及以上权限可见打赏记录
            if (this.admin_boxcoin_visible === 0) {
                return this.userId == this.user.uid || this.user.group >= 64;
            }
            return true;
        },
    },
    watch: {
        post_keys: {
            immediate: true,
            deep: true,
            handler: function () {
                this.postType && this.postId && this.loadBoxcoinConfig();
            },
        },
    },
    methods: {
        resetBoxcoinQuota() {
            this.admin_max = 0;
            this.admin_min = 0;
            this.admin_left = 0;
            this.admin_total = 0;
            this.admin_points = [100];
            this.total_limit = 0;
            this.post_type_used = 0;
            this.user_left = 0;
            this.user_points = [100];
        },
        loadBoxcoinConfig: function () {
            User.isLogin() &&
                getPostBoxcoinConfig(this.postType)
                    .then((res) => {
                        this.admin_max = res.data.data.limit.admin_max || 0;
                        this.admin_min = res.data.data.limit.admin_min || 0;
                        this.admin_points = res.data.data.limit.admin_points || [10, 1000];
                        this.admin_left = res.data.data.asManagerBoxCoinRemain || 0;
                        this.admin_total = res.data.data.asManagerBoxCoinTotal || 0;
                        this.total_limit = res.data.data.limit.total_limit || 0;
                        this.post_type_used = res.data.data.asPostTypeBoxcoinHasUsedTotalAtCurrentYear || 0;

                        this.user_points = res.data.data.limit.user_points || [10, 1000];
                        // 根据多端展示剩余币
                        // 作品是n端，接受n端币+all币
                        if (this.finalClient == "origin") {
                            this.user_left = res.data.data.asUserBoxCoinRemainOrigin + res.data.data.asUserBoxCoinRemainAll;
                        } else if (this.finalClient == "std") {
                            this.user_left = res.data.data.asUserBoxCoinRemainStd + res.data.data.asUserBoxCoinRemainAll;
                        } else {
                            this.user_left =
                                res.data.data.asUserBoxCoinRemainAll +
                                res.data.data.asUserBoxCoinRemainStd +
                                res.data.data.asUserBoxCoinRemainOrigin;
                        }
                    })
                    .catch(() => {
                        this.resetBoxcoinQuota();
                    });
            getBoxcoinStatus()
                .then((res) => {
                    this.boxcoin_enable = !!~~res.data?.data?.val;
                })
                .catch(() => {
                    this.boxcoin_enable = 0;
                });

            getConfig({
                key: "admin_boxcoin_visible",
            })
                .then((res) => {
                    this.admin_boxcoin_visible = Number(res?.val);
                })
                .catch(() => {
                    this.admin_boxcoin_visible = 1;
                });

            getConfig({
                key: `level_has_gift_permission`,
            })
                .then((res) => {
                    User.isLogin() &&
                        User.getAsset()
                            .then((data) => {
                                const asset = data;
                                this.lvEnough = asset && asset.experience >= Number(res?.val);
                            })
                            .catch(() => {
                                this.lvEnough = false;
                            });
                })
                .catch(() => {
                    this.lvEnough = false;
                });

            User.isLogin() &&
                getUserPermission()
                    .then((res) => {
                        const permissions = res.data.data.permission?.map((item) => item.action);
                        this.hasPermission = permissions.includes(`manage_boxcoin_${this.postType}`);
                    })
                    .catch(() => {
                        this.hasPermission = false;
                    });
        },
        // 用户打赏
        updateRecord: function (data) {
            this.cacheRecord = data;
        },
        updateBoxcoin: function (data) {
            this.boxcoin = data;
        },
    },
};
</script>

