left-inner::-webkit-resizer {\n  display: none;\n}\n@media screen and (max-width: 1680px) {\n  .c-sidebar-left {\n    width: 280px;\n  }\n}\n@media screen and (max-width: 1440px) {\n  .c-sidebar-left {\n    width: 260px;\n  }\n}\n@media screen and (max-width: 720px) {\n  .c-sidebar-left-inner {\n    overflow-y: auto;\n  }\n}\n.c-sidebar-left-toggle {\n  display: block;\n  position: absolute;\n  right: -21px;\n  bottom: calc(50% - 20px);\n  width: 20px;\n  height: 40px;\n  line-height: 40px;\n  cursor: pointer;\n  text-align: center;\n  background-color: #fafbfc;\n  border-right: 1px solid #eee;\n  border-top: 1px solid #eee;\n  border-bottom: 1px solid #eee;\n  border-radius: 0px 2px 2px 0px;\n  font-size: 16px;\n  color: #999;\n}\n.c-sidebar-left-toggle:hover {\n  color: #222;\n}\n.c-sidebar-left-toggle.close-sidebar-left {\n  right: 0;\n}\n.c-sidebar-left-toggle svg {\n  fill: #3d454d;\n}\n.c-sidebar-left.isclose {\n  transition: 0.2s ease-in-out;\n  transform: translateX(-100%);\n}\n.c-sidebar-left.isclose .c-sidebar-left-toggle {\n  transition: 0.2s ease-in-out;\n  transform: translateX(100%);\n}\n.c-sidebar-left.isopen {\n  transition: 0.2s ease-in-out;\n  transform: translateX(0);\n}\n.c-sidebar-left.isopen .c-sidebar-left-toggle {\n  transition: 0.2s ease-in-out;\n  transform: translateX(0);\n}\n@media screen and (max-width: 1133px) {\n  .c-sidebar-left-toggle {\n    display: none;\n  }\n  .c-sidebar-left.isopen {\n    box-shadow: 2px 0 3px rgba(0, 0, 0, 0.1);\n  }\n}\n@media print {\n  .c-sidebar-left {\n    display: none;\n  }\n}\n.m-theme {\n  background-repeat: no-repeat;\n  background-size: contain;\n  background-position: top right;\n}\n/*# sourceMappingURL=LeftSidebar.css.map */","/* assets/css/common/left-sidebar.less */\n.c-sidebar-left {\n    .w(@aside-left - 40px);\n    box-sizing: border-box;\n    padding: 10px;\n    .pf;\n    .z(600);\n    left: 0;\n    top: @header-height + @bread-height;\n    bottom: 0;\n    background-color: @bg-light;\n    border-right: 1px solid #eee;\n}\n\n.c-sidebar-left.without-bread {\n    top: @header-height;\n}\n\n.c-sidebar-left-inner {\n    .size(100%);\n    overflow-y: auto;\n\n    &::-webkit-scrollbar {\n        width: 4px;\n    }\n\n    &::-webkit-scrollbar-track,\n    &::-webkit-scrollbar-track-piece {\n        background-color: #fafafa;\n        border-radius: 6px;\n    }\n\n    &::-webkit-scrollbar-thumb {\n        background-color: #eee;\n        border-radius: 6px;\n    }\n\n    &::-webkit-scrollbar-button,\n    &::-webkit-scrollbar-corner,\n    &::-webkit-resizer {\n        display: none;\n    }\n}\n\n// 笔记本<1440 缩小双边栏\n@media screen and (max-width: @smallpc) {\n    .c-sidebar-left {\n        .w(@aside-left - 40px);\n    }\n}\n\n// 平板横屏\n@media screen and (max-width: @notebook) {\n    .c-sidebar-left {\n        .w(@aside-left - 60px);\n    }\n}\n\n@media screen and (max-width: @phone) {\n    .c-sidebar-left-inner {\n        overflow-y: auto;\n    }\n}\n\n// 折叠相关逻辑\n.c-sidebar-left-toggle {\n    display: block;\n    .pa;\n    .rb(-21px, calc(50% - 20px));\n    width: 20px;\n    height: 40px;\n    line-height: 40px;\n    .pointer;\n    text-align: center;\n    background-color: @bg-light;\n    border-right: 1px solid #eee;\n    border-top: 1px solid #eee;\n    border-bottom: 1px solid #eee;\n    border-radius: 0px 2px 2px 0px;\n    font-size: 16px;\n    color: #999;\n\n    &:hover {\n        color: #222;\n    }\n\n    &.close-sidebar-left {\n        right: 0;\n    }\n\n    svg {\n        fill: @color;\n    }\n}\n\n.closeLeftSidebar() {\n    transition: 0.2s ease-in-out;\n    transform: translateX(-100%);\n}\n\n.openLeftSidebar() {\n    transition: 0.2s ease-in-out;\n    transform: translateX(0);\n}\n\n.c-sidebar-left.isclose {\n    .closeLeftSidebar();\n\n    .c-sidebar-left-toggle {\n        transition: 0.2s ease-in-out;\n        transform: translateX(100%);\n    }\n}\n\n.c-sidebar-left.isopen {\n    .openLeftSidebar();\n\n    .c-sidebar-left-toggle {\n        transition: 0.2s ease-in-out;\n        transform: translateX(0);\n    }\n}\n\n@media screen and (max-width: @ipad) {\n    .c-sidebar-left-toggle {\n        .none;\n    }\n\n    .c-sidebar-left.isopen {\n        box-shadow: 2px 0 3px rgba(0, 0, 0, 0.1);\n    }\n}\n\n@media print {\n    .c-sidebar-left {\n        .none;\n    }\n}\n","// 路径\n@img: \"https://img.jx3box.com/\";\n@cdn: \"https://cdn.jx3box.com/\";\n@cdnimg: \"https://cdn.jx3box.com/img/\";\n@image: \"https://cdn.jx3box.com/image/\";\n@pic: \"https://cdn.jx3box.com/pic/\";\n@font: \"https://cdn.jx3box.com/img/font/\";\n\n// 配色·旧\n@color: #3d454d;\n@primary: #0366d6;\n@bg-black: #24292e;\n@bg-gray: #f6f8fa;\n@bg-light: #fafbfc;\n@color-link: #0366d6;\n@border-hr: #e1e4e8;\n@pink: #f39;\n@light-pink: #f9afd4;\n@blue: #409eff;\n@darkblue: #359;\n@grayblue: #7e93ac;\n@border: #e4e7ed;\n@purple: #6f42c1;\n\n// 配色·v4\n@v4primary: #4f46e5;\n@v4primary-bg: #7d86fb;\n@v4primary-dark: #4b3bed;\n@v4font: #4338ca;\n@v4primary500: #615fff;\n\n@v4border: #c7d2fe;\n@v4bg: #f2f5ff;\n\n@v4text: #4f667d;\n@v4tip: #989cb1;\n\n@v4focus: #efb23e;\n@v4orange: #ec9c0f;\n@v4yellow: #f5bd1e;\n\n@v4pink: #f9c;\n\n// 布局（全局公共组件）\n@header-height: 60px;\n@header-logo-size: 32px;\n@header-bg: #242424;\n@bread-height: 48px;\n\n@aside-left: 320px;\n@aside-right: 280px;\n\n@footer-bg: #121827;\n\n// 适配\n@4k: 3840px;\n@2k: 2560px;\n@pc: 1920px;\n@smallpc: 1680px; //21寸显示器\n@notebook: 1440px; //笔记本电脑\n@mininote: 1280px; //小屏笔记本\n@ipad: 1133px; //平板，适配到8.3mini6\n@ipad-y: 1023px; //竖屏\n@game: 780px; //游戏内嵌\n@phone: 720px; //手机\n@ip5: 374px; //iphone5超小屏\n\n/* assets/css/var.less */\n// ⚠️请勿删除\n/* assets/css/mixin.less */\n// ⚠️请勿删除\n\n// 三角\n.u-delta() {\n    .pa;\n    background-clip: padding-box;\n    background-color: #fff;\n    color: @color;\n    border: 1px solid rgba(27, 31, 35, 0.15);\n    border-radius: 4px;\n    box-shadow: 0 3px 12px rgba(0, 0, 0, 0.1);\n    right: -5px;\n    list-style: none;\n    margin: -6px 0 0 0;\n    position: absolute;\n    z-index: 820;\n    top: 100%;\n\n    &:before {\n        content: \"\";\n        display: inline-block;\n        position: absolute;\n        left: auto;\n        right: 14px;\n        top: -16px;\n        border: 8px solid transparent;\n        border-bottom-color: rgba(27, 31, 35, 0.15);\n    }\n\n    &:after {\n        content: \"\";\n        display: inline-block;\n        position: absolute;\n        left: auto;\n        right: 15px;\n        top: -14px;\n        border: 7px solid transparent;\n        border-bottom-color: #fff;\n    }\n}\n/*\n * Base.less\n * Author: iRuxu\n * Description: a simple and easy-to-use CSS framework, providing common writing combinations\n * Manual: http://csslab.cc\n */\n\n\n/* Font -------------------------------------*/\n\n    // Font size & line height\n    .fz(@font-size, @line-height: false) {\n        font-size: @font-size;\n        & when not (@line-height = false) {\n            line-height: @line-height;\n        }\n    }\n\n    // line height\n    .lh(@line-height, @height: false) {\n        line-height: @line-height;\n        & when not (@height = false) {\n            height: @height;\n        }\n    }\n\n    // Font style\n    .bold(@bold:bold){font-weight:@bold;}\n\n    .italic(){font-style:italic;}\n\n    .normal(){font-weight:normal;font-style:normal;}\n\n    .smooth(){\n        -webkit-font-smoothing:antialiased;\n        -moz-osx-font-smoothing:grayscale;\n    }\n\n    // Number\n    .number(@font-family: false) {\n        & when (@font-family = true) {\n            font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, \"Liberation Mono\", monospace;\n        }\n\n        & when (isstring(@font-family)) {\n            font-family: e(@font-family);\n        }\n\n        font-variant-numeric: tabular-nums slashed-zero;\n        font-feature-settings: \"tnum\" 1, \"zero\" 1;\n    }\n\n    // Font-Face\n    // 注意传参时，name后接分号\n    .fontface(@name; @sources...) {\n        @font-face {\n            font-family: @name;\n            src: @sources;\n            font-display: swap;\n        }\n    }\n\n    // Font color\n    .color(@color, @hovercolor: null) {\n        // 检查是否为纯色\n        & when (iscolor(@color)) {\n            color: @color;\n\n            & when (iscolor(@hovercolor)) {\n                &:hover {\n                    color: @hovercolor;\n                }\n            }\n        }\n        // 非纯色处理（背景填充逻辑）\n        & when not (iscolor(@color)) {\n            -webkit-background-clip: text;\n            -webkit-text-fill-color: transparent;\n            background-image: @color;\n        }\n    }\n\n    // Underline\n    .underline() {\n        .underline(3px, solid, currentColor);\n    }\n\n    .underline(@color) when (iscolor(@color)) {\n        .underline(3px, solid, @color);\n    }\n\n    .underline(@offset, @style, @color) {\n        text-decoration: underline;\n        text-decoration-color: @color;\n        text-decoration-style: @style;\n        text-underline-offset: @offset;\n    }\n\n\n/* Word -------------------------------------*/\n\n    // 不折行\n    .nobreak(@style:ellipsis){\n        white-space:nowrap;\n        word-break:keep-all;\n\n        word-wrap:normal;\n        overflow-wrap: normal;\n\n        text-overflow:@style;\n        overflow:hidden;\n    }\n\n    // 折行\n    .break(@lines: auto, @inline: false) {\n        // 单行折行处理\n        & when (@lines = auto) {\n            white-space: normal;\n            word-break: break-all;\n            word-wrap: break-word;\n            overflow-wrap: break-word;\n            hyphens: auto;\n            line-break: strict;\n        }\n        // 多行折行处理\n        & when not (@lines = auto) {\n            display: if(@inline, -webkit-inline-box, -webkit-box);\n            -webkit-line-clamp: @lines;\n            -webkit-box-orient: vertical;\n            overflow: hidden;\n        }\n    }\n\n    // Special Write Mode\n    // 书写模式：牌匾从右至左水平单行排版效果\n    .retext(x){direction:rtl;unicode-bidi:bid