<template>
    <div class="c-header-msg" id="c-header-msg">
        <el-tooltip
            effect="dark"
            :content="$jx3boxT('jx3boxUi.commonHeader.messageCenter', '消息中心')"
            placement="bottom"
            popper-class="c-header-tooltip"
        >
            <a class="u-msg" :href="url">
                <i class="u-icon u-icon-msg">
                    <i class="u-pop" style="display: none" v-show="pop"></i>
                    <!-- <bell /> -->
                    <img
                        svg-inline
                        src="../../assets/img/common/bell.svg"
                        :alt="$jx3boxT('jx3boxUi.commonHeader.messageCenter', '消息中心')"
                    />
                </i>
            </a>
        </el-tooltip>
    </div>
</template>

<script>
import JX3BOX from "@jx3box/jx3box-common/data/jx3box.json";
import { getLetter, getMsg } from "../../service/header";
import i18nMixin from "../../i18n/mixin";
// import bell from "@/assets/img/components/common/header/bell.svg";
export default {
    name: "message",
    mixins: [i18nMixin],
    components: {
        // bell,
    },
    data: function () {
        return {
            url: JX3BOX.__Links.dashboard.msg,
            pop: false,
        };
    },
    mounted() {
        this.checkMSG();
    },
    methods: {
        // 消息
        checkMSG: async function () {
            const letterRes = await getLetter();
            const msgRes = await getMsg();
            this.pop = !!(Math.max(~~letterRes.data.data.letter, 0) || Math.max(~~msgRes.data.data.unread_count, 0));
        },
    },
};
</script>

