argin-top:@margin;}\n    .mb(@margin){margin-bottom:@margin;}\n\n    .tm(@tm){\n        @alpha:@tm*100;\n        opacity:@tm; //ie9 webkit etc.\n        filter:alpha(opacity=@alpha); //ie5-ie7\n    }\n\n\n\n\n/* src/single/Comment.vue */\n.c-comment {\n    font-size: 14px;\n    .el-link {\n        vertical-align: baseline !important;\n    }\n    .el-icon-circle-close {\n        color: #fff !important;\n    }\n}\n.c-comment-mask {\n    .u-mask {\n        display: block;\n        font-size: 13px;\n    }\n}\n.u-uploader {\n    margin-top: 10px;\n}\n.c-comment .el-main {\n    padding: 0;\n}\n.c-comment-box {\n    margin: 12px 0;\n    border-bottom: 1px solid #eee;\n    textarea {\n        font-family: inherit;\n    }\n    .u-publish {\n        float: right;\n        margin-top: 10px;\n    }\n\n    .el-form-item__content {\n        flex-direction: column;\n        align-items: flex-start;\n    }\n\n    .u-toolbar {\n        display: flex;\n        align-items: center;\n        justify-content: flex-end;\n        width: 100%;\n    }\n}\n\n.c-comment-tools {\n    display: flex;\n    align-items: center;\n    overflow: hidden;\n    height: 48px;\n\n    .u-upload-icon {\n        font-size: 24px;\n        cursor: pointer;\n        margin-right: 10px;\n        // margin-left: 10px;\n        color: #555;\n        .pr;top:-1px;\n\n        &:hover {\n            color: var(--el-color-primary);\n        }\n    }\n    .c-jx3box-emotion {\n        margin: 0;\n        position: relative;\n    }\n    .c-comment-emotion {\n        overflow: hidden;\n    }\n}\n\n.c-comment-list {\n    padding: 10px 0;\n    margin-bottom: 10px;\n    border-bottom: 1px solid #eee;\n    display: flex;\n}\n\n.c-comment-pages {\n    *zoom: 1;\n    &:after {\n        content: \"\";\n        display: table;\n        clear: both;\n    }\n    .u-quickreply {\n        float: left;\n        input {\n            width: 360px;\n        }\n    }\n    .u-pages {\n        float: right;\n    }\n}\n@media screen and (max